import{_ as t,c as a,o,ag as n}from"./chunks/framework.DD2hp6gW.js";const g=JSON.parse('{"title":"Number Input Field","description":"","frontmatter":{},"headers":[],"relativePath":"fields/number.md","filePath":"fields/number.md","lastUpdated":null}'),l={name:"fields/number.md"};function r(i,e,s,d,c,h){return o(),a("div",null,e[0]||(e[0]=[n('<h1 id="number-input-field" tabindex="-1">Number Input Field <a class="header-anchor" href="#number-input-field" aria-label="Permalink to &quot;Number Input Field&quot;">​</a></h1><p>The <strong>Number Input</strong> field restricts the customer&#39;s input strictly to numeric values. The browser renders a native number spinner, and OptionBay enforces minimum, maximum, and step constraints both on the frontend and during server-side validation.</p><h2 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h2><ul><li>Custom dimensions (length, width, height in cm or inches)</li><li>Selecting a quantity of a specific add-on item</li><li>Specifying an age, weight, or other measurement</li><li>Entering a custom number for pricing calculations (e.g., square footage)</li></ul><h2 id="field-settings" tabindex="-1">Field Settings <a class="header-anchor" href="#field-settings" aria-label="Permalink to &quot;Field Settings&quot;">​</a></h2><p>When you add a Number field and expand it in the builder, the following settings are available:</p><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The title displayed above the input on the product page (e.g., &quot;Width (cm)&quot;).</td></tr><tr><td style="text-align:left;"><strong>Description</strong></td><td style="text-align:left;">Optional help text shown below the input (e.g., &quot;Enter a value between 10 and 200&quot;).</td></tr><tr><td style="text-align:left;"><strong>Required</strong></td><td style="text-align:left;">When checked, the customer must enter a number before adding the product to the cart.</td></tr></tbody></table><h3 id="placeholder" tabindex="-1">Placeholder <a class="header-anchor" href="#placeholder" aria-label="Permalink to &quot;Placeholder&quot;">​</a></h3><p>You can set <strong>Placeholder</strong> text that appears inside the number input (e.g., &quot;Enter width&quot;).</p><h3 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h3><p>Since the Number field is not an options-based field, pricing is configured at the <strong>field level</strong>:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Price Type</strong></td><td style="text-align:left;">Choose how the field affects the product price. Available types: <strong>No Price</strong>, <strong>Flat Fee</strong>, <strong>Percentage of Base</strong>, or <strong>Formula</strong>.</td></tr><tr><td style="text-align:left;"><strong>Price Amount</strong></td><td style="text-align:left;">The numeric value to apply.</td></tr><tr><td style="text-align:left;"><strong>Formula</strong></td><td style="text-align:left;">(Only when Price Type is &quot;Formula&quot;) A math expression using placeholders like <code>[value]</code>, <code>[base_price]</code>, and <code>[quantity]</code>. Example: <code>[value] * 2.50</code> charges $2.50 per unit of the entered number.</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>The <strong>Formula</strong> price type is especially powerful with number fields. For example, if your customer enters the square footage of a room, you can use <code>[value] * 3.00</code> to charge $3.00 per square foot.</p></div><h3 id="restrictions" tabindex="-1">Restrictions <a class="header-anchor" href="#restrictions" aria-label="Permalink to &quot;Restrictions&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Min</strong></td><td style="text-align:left;">The lowest numeric value the customer can enter.</td></tr><tr><td style="text-align:left;"><strong>Max</strong></td><td style="text-align:left;">The highest numeric value the customer can enter.</td></tr><tr><td style="text-align:left;"><strong>Step Value</strong></td><td style="text-align:left;">Defines the legal number intervals. A step of <code>0.5</code> allows <code>1.0</code>, <code>1.5</code>, <code>2.0</code>, etc. A step of <code>1</code> only allows whole numbers. Defaults to <code>1</code>.</td></tr></tbody></table><h2 id="conditional-logic" tabindex="-1">Conditional Logic <a class="header-anchor" href="#conditional-logic" aria-label="Permalink to &quot;Conditional Logic&quot;">​</a></h2><p>You can show or hide this field based on the value of another field in the same group. For example, show a &quot;Width&quot; number field only when the customer selects &quot;Custom Size&quot; from a dropdown.</p><p>For full details on setting up rules, see the <a href="./../conditional-logic.html">Conditional Logic</a> page.</p>',19)]))}const p=t(l,[["render",r]]);export{g as __pageData,p as default};
